Scoop# 适用于 Windows 的命令行安装程序
参考# https://scoop.sh/
命令# # 搜索 scoop search &lt;app_name&gt; # 卸载 scoop uninstall &lt;app_name&gt; # 查看已安装 scoop list # 更新 scoop 和 bucket scoop update # 更新所有 scoop update * # 禁止更新指定app scoop hold &lt;app_name&gt; # 解除禁止更新app scoop unhold &lt;app_name&gt; # 安装特点版本 scoop install &lt;app&gt;@&lt;version&gt;` # 清理旧版本 scoop cleanup &lt;app_name&gt;

Wsl debian# 我的默认base debian
安装wsl# # 版本 wsl --list --online # 安装debian wsl --install -d Debian禁用 WSL 的 Windows$PATH 互操作性# # 运行以下命令以**root权限**打开文件： sudo vi /etc/wsl.conf # 输入您的 WSL 用户密码。 # 单击`i`进入编辑模式（插入模式）。 # 输入或修改内容： [interop] appendWindowsPath = false # 单击`Esc`退出编辑模式。 # 输入`:wq`(保存并退出)。 # 修改`/etc/wsl.conf`后，您必须完全关闭并重新启动 WSL 才能更改生效。 wsl --shutdown进入wsl# # base sudo apt update &amp;&amp; sudo apt install -y curl wget vim git build-essential iputils-ping net-tools htop dnsutils unzip zip procps sudo apt install git-lfs git lfs install # 清理安装产生的缓存，节省 WSL 空间 sudo apt autoremove -y &amp;&amp; sudo apt clean安装脚本# 安装 lazygit
#!/bin/bash # set -e ARCH=$(uname -m) case &#34;$ARCH&#34; in x86_64) BIN_ARCH=&#34;x86_64&#34; ;; aarch64|arm64) BIN_ARCH=&#34;arm64&#34; ;; *) echo &#34;❌ 架构不支持: $ARCH&#34;; exit 1 ;; esac echo &#34;🔍 正在搜索最新版 Lazygit...&#34; URL_LATEST=&#34;https://github.com/jesseduffield/lazygit/releases/latest&#34; REAL_URL=$(curl -Ls -o /dev/null -w %{url_effective} &#34;$URL_LATEST&#34;) TAG=$(basename &#34;$REAL_URL&#34;) VERSION=${TAG#v} FILE=&#34;lazygit_${VERSION}_Linux_${BIN_ARCH}.tar.gz&#34; URL=&#34;https://github.com/jesseduffield/lazygit/releases/download/${TAG}/${FILE}&#34; echo &#34;📥 正在下载 $FILE 到当前目录...&#34; curl -L -O &#34;$URL&#34; echo &#34;📦 正在安装...&#34; tar -xzf &#34;$FILE&#34; lazygit sudo install -m 755 lazygit /usr/local/bin/lazygit rm -f &#34;$FILE&#34; lazygit echo &#34;✅ lazygit 安装完成。&#34; lazygit --version 安装btop
#!/bin/bash set -e ARCH=$(uname -m) case &#34;$ARCH&#34; in x86_64) FILE=&#34;btop-x86_64-unknown-linux-musl.tbz&#34; ;; aarch64|arm64) FILE=&#34;btop-aarch64-unknown-linux-musl.tbz&#34; ;; *) echo &#34;❌ 架构不支持: $ARCH&#34;; exit 1 ;; esac URL=&#34;https://github.com/aristocratos/btop/releases/latest/download/$FILE&#34; echo &#34;📥 正在下载 $FILE 到当前目录...&#34; curl -L -O &#34;$URL&#34; echo &#34;📦 正在安装并自动清理...&#34; tar -xjf &#34;$FILE&#34; sudo install -m 755 btop/bin/btop /usr/local/bin/btop rm -rf &#34;$FILE&#34; btop echo &#34;✅ btop 安装成功。&#34; btop --version 安装eza
#!/bin/bash set -e ARCH=$(uname -m) case &#34;$ARCH&#34; in x86_64) FILE=&#34;eza_x86_64-unknown-linux-gnu.tar.gz&#34; ;; aarch64|arm64) FILE=&#34;eza_aarch64-unknown-linux-gnu.tar.gz&#34; ;; *) echo &#34;❌ 架构不支持: $ARCH&#34;; exit 1 ;; esac URL=&#34;https://github.com/eza-community/eza/releases/latest/download/$FILE&#34; echo &#34;📥 正在下载 $FILE 到当前目录...&#34; curl -L -O &#34;$URL&#34; echo &#34;📦 正在解压并安装...&#34; tar -xzf &#34;$FILE&#34; sudo install -m 755 eza /usr/local/bin/eza rm -f &#34;$FILE&#34; eza echo &#34;✅ eza 安装完成。&#34; eza --version 安装neovim
#!/bin/bash set -e ARCH=$(uname -m) case &#34;$ARCH&#34; in x86_64) BIN_ARCH=&#34;x86_64&#34; ;; aarch64|arm64) BIN_ARCH=&#34;arm64&#34; ;; *) echo &#34;❌ 架构不支持: $ARCH&#34;; exit 1 ;; esac FILE=&#34;nvim-linux-${BIN_ARCH}.tar.gz&#34; DIR_NAME=&#34;nvim-linux-${BIN_ARCH}&#34; URL=&#34;https://github.com/neovim/neovim/releases/latest/download/${FILE}&#34; echo &#34;🔍 正在从官方获取 $BIN_ARCH 版 Neovim...&#34; curl -LO &#34;$URL&#34; echo &#34;📦 正在安装至 /opt...&#34; sudo rm -rf &#34;/opt/$DIR_NAME&#34; sudo tar -C /opt -xzf &#34;$FILE&#34; rm -f &#34;$FILE&#34; echo &#34;------------------------------------------&#34; echo &#34;✅ Neovim 已成功解压到 /opt/$DIR_NAME&#34; if [[ &#34;:$PATH:&#34; == *&#34;:/opt/$DIR_NAME/bin:&#34;* ]]; then echo &#34;🚀 PATH 已经配置好了。&#34; else echo &#34;⚠️ 请手动将以下行添加到您的 ~/.bashrc 或 ~/.zshrc 中：&#34; echo &#34; export PATH=\&#34;\$PATH:/opt/$DIR_NAME/bin\&#34;&#34; echo &#34; 然后执行: source ~/.bashrc (或 source ~/.zshrc)&#34; fi echo &#34;------------------------------------------&#34; /opt/$DIR_NAME/bin/nvim --version | head -n 1 安装tmux
#!/bin/bash set -e ARCH=$(uname -m) case &#34;$ARCH&#34; in x86_64) BIN_ARCH=&#34;x86_64&#34; ;; aarch64|arm64) BIN_ARCH=&#34;arm64&#34; ;; *) echo &#34;❌ 架构不支持: $ARCH&#34;; exit 1 ;; esac echo &#34;🔍 正在搜索最新版 Tmux...&#34; URL_LATEST=&#34;https://github.com/tmux/tmux-builds/releases/latest&#34; REAL_URL=$(curl -Ls -o /dev/null -w %{url_effective} &#34;$URL_LATEST&#34;) TAG=$(basename &#34;$REAL_URL&#34;) VERSION=${TAG#v} FILE=&#34;tmux-${VERSION}-linux-${BIN_ARCH}.tar.gz&#34; URL=&#34;https://github.com/tmux/tmux-builds/releases/download/${TAG}/${FILE}&#34; echo &#34;📥 正在下载 $FILE 到当前目录...&#34; curl -L -O &#34;$URL&#34; echo &#34;📦 正在安装并自动清理...&#34; tar -xzf &#34;$FILE&#34; tmux sudo install -m 755 tmux /usr/local/bin/tmux rm -f &#34;$FILE&#34; tmux echo &#34;✅ tmux 安装完成。&#34; tmux -V 安装yazi
#!/bin/bash set -e ARCH=$(uname -m) case &#34;$ARCH&#34; in x86_64) FILE=&#34;yazi-x86_64-unknown-linux-gnu.deb&#34; ;; aarch64|arm64) FILE=&#34;yazi-aarch64-unknown-linux-gnu.deb&#34; ;; *) echo &#34;❌ 架构不支持&#34;; exit 1 ;; esac URL=&#34;https://github.com/sxyazi/yazi/releases/latest/download/$FILE&#34; echo &#34;📥 正在下载 $FILE 到当前目录...&#34; curl -L -O &#34;$URL&#34; echo &#34;📦 正在安装并自动清理本地包...&#34; sudo apt install -y &#34;./$FILE&#34; &amp;&amp; rm &#34;$FILE&#34; echo &#34;✅ 安装成功，已自动清除 $FILE。&#34; yazi --version
